const fs = require\('fs'\);
let content = fs.readFileSync\('src/routes/+page.svelte', 'utf8'\);
const lines = content.split\('\\n'\);

// 1. Remove desktop button row: lines 257-403 \(0-indexed\), replace with nothing
// Line 257 \(0-indexed\) = '\\t\\t\\t<!-- Desktop: all buttons \(md and up\) -->'
// Line 402 \(0-indexed\) = '\\t\\t\\t</div>'
// Line 403 \(0-indexed\) = ''
// Keep line 403 \(empty line\) as separator
const newLines = [
  ...lines.slice\(0, 257\),      // everything before desktop block
  ...lines.slice\(403\)           // empty line + hamburger + rest
];

// 2. Remove 'md:hidden' from the hamburger wrapper div
// Find the line with 'relative md:hidden'
for \(let i = 0; i < newLines.length; i++\) {
  if \(newLines[i].includes\('relative md:hidden'\)\) {
    newLines[i] = newLines[i].replace\('relative md:hidden', 'relative'\);
    console.log\('Fixed hamburger wrapper at line', i+1\);
    break;
  }
}

// 3. Remove 'md:hidden' from the backdrop div
for \(let i = 0; i < newLines.length; i++\) {
  if \(newLines[i].includes\('fixed inset-0 z-40 md:hidden'\)\) {
    newLines[i] = newLines[i].replace\('fixed inset-0 z-40 md:hidden', 'fixed inset-0 z-40'\);
    console.log\('Fixed backdrop at line', i+1\);
    break;
  }
}

// 4. Remove 'md:hidden' from the dropdown panel div
for \(let i = 0; i < newLines.length; i++\) {
  if \(newLines[i].includes\('fixed top-14 right-2 z-50'\) && newLines[i].includes\('md:hidden'\)\) {
    newLines[i] = newLines[i].replace\(' md:hidden', ''\);
    console.log\('Fixed dropdown panel at line', i+1\);
    break;
  }
}

// 5. Update the comment from 'Mobile: hamburger' to just 'Menu'
for \(let i = 0; i < newLines.length; i++\) {
  if \(newLines[i].includes\('<!-- Mobile: hamburger \(below md\) -->'\)\) {
    newLines[i] = newLines[i].replace\('<!-- Mobile: hamburger \(below md\) -->', '<!-- Hamburger menu -->'\);
    console.log\('Updated comment at line', i+1\);
    break;
  }
}

fs.writeFileSync\('src/routes/+page.svelte', newLines.join\('\\n'\)\);
console.log\('Done. Total lines:', newLines.length\);
")

